380	///     else { luaL_pushfail; pushlstring("exit"|"signal"); pushinteger(stat); return 3; }`
381	///
382	/// TODO(port): POSIX `WIFEXITED`/`WTERMSIG` macros not available on all platforms;
383	/// this stub always treats non-zero stat as an exit code.
384	fn exec_result(state: &mut LuaState, stat: i32) -> Result<usize, LuaError> {
385	    if stat == 0 {
386	        state.push(LuaValue::Bool(true));
387	        Ok(1)
388	    } else {
389	        state.push(LuaValue::Bool(false));
390	        // TODO(port): distinguish exit vs signal via POSIX macros
391	        state.push_string(b"exit");
392	        state.push(LuaValue::Int(stat as i64));
393	        Ok(3)
394	    }
395	}
396	
397	/// Retrieve `LStream` from argument 1 via a userdata type-check.
398	/// C: `tolstream(L)` = `(LStream *)luaL_checkudata(L, 1, LUA_FILEHANDLE)`.
399	///
400	/// Returns an `Rc<RefCell<LStream>>` from the side-table registry. The C port
401	/// returns a raw `LStream *` pointing into the userdata payload; Rust uses a
402	/// side table because `LStream` contains heap pointers that cannot be safely
403	/// reinterpreted from a raw byte buffer in safe Rust.
404	fn get_lstream(state: &mut LuaState) -> Result<Rc<RefCell<LStream>>, LuaError> {
405	    let ud = state.check_arg_userdata(1, LUA_FILE_HANDLE)?;
406	    lookup_lstream(ud.identity()).ok_or_else(|| {
407	        LuaError::runtime(format_args!("invalid file handle"))
408	    })
409	}
410	
411	/// Validate that argument 1 is an open file handle; error if closed.
412	/// C: `tofile` (returns `FILE *` in C; here we return the wrapping `Rc<RefCell<LStream>>`).
413	fn tofile(state: &mut LuaState) -> Result<Rc<RefCell<LStream>>, LuaError> {
414	    let p_rc = get_lstream(state)?;
415	    {
416	        let p = p_rc.borrow();
417	        // C: if (isclosed(p)) luaL_error(L, "attempt to use a closed file");
418	        if p.is_closed() {
419	            return Err(LuaError::runtime(format_args!(
420	                "attempt to use a closed file"
421	            )));
422	        }
423	        // C: lua_assert(p->f);
424	        debug_assert!(p.file.is_some());
425	    }
426	    Ok(p_rc)
427	}
428	
429	// ── File creation helpers ────────────────────────────────────────────────────
430	
431	/// Allocate a "closed" file-handle userdata and push it; set its metatable.
432	/// Also registers an empty `LStream` in the side table keyed by the userdata
433	/// identity, and returns the `Rc<RefCell<LStream>>` so the caller may finish
434	/// initialising it (set `file`, set `close_fn`). C: `newprefile(L)`.
435	fn new_pre_file(state: &mut LuaState) -> Result<Rc<RefCell<LStream>>, LuaError> {
436	    // C: LStream *p = lua_newuserdatauv(L, sizeof(LStream), 0);
437	    let ud = state.new_userdata_typed(LUA_FILE_HANDLE, std::mem::size_of::<LStream>(), 0)?;
438	    // C: luaL_setmetatable(L, LUA_FILEHANDLE);
439	    state.set_metatable_by_name(LUA_FILE_HANDLE)?;
440	    // C: p->closef = NULL;  (LStream::close_fn = None marks the stream as closed)
441	    let cell = register_lstream(ud.identity(), LStream { file: None, close_fn: None });
442	    Ok(cell)
443	}
444	
445	/// Allocate a new regular-file handle with `io_fclose` as the close function.
446	/// C: `newfile(L)`.
447	fn new_file(state: &mut LuaState) -> Result<Rc<RefCell<LStream>>, LuaError> {
448	    // C: LStream *p = newprefile(L); p->f = NULL; p->closef = &io_fclose;
449	    let cell = new_pre_file(state)?;
450	    cell.borrow_mut().close_fn = Some(io_fclose);
451	    Ok(cell)
452	}
453	
454	/// Open `fname` and push its handle; raise a runtime error on failure.
455	/// C: `opencheck(L, fname, mode)`.
456	///
457	/// The file system is reached via `GlobalState::file_open_hook` (registered by
458	/// `lua-cli`) since `std::fs` is banned in `lua-stdlib` per PORTING.md §1.
459	fn opencheck(state: &mut LuaState, fname: &[u8], mode: &[u8]) -> Result<(), LuaError> {
460	    let hook = state.global().file_open_hook;
461	    let fh = match hook {
462	        Some(open_fn) => open_fn(fname, mode).map_err(|e| {
463	            LuaError::runtime(format_args!(
464	                "cannot open file '{}' ({})",
465	                fname.escape_ascii(),
466	                match &e {
467	                    LuaError::Runtime(LuaValue::Str(s)) => {
468	                        String::from_utf8_lossy(s.as_bytes()).into_owned()
469	                    }
470	                    other => format!("{:?}", other),
471	                }
472	            ))
473	        })?,
474	        None => {
475	            return Err(LuaError::runtime(format_args!(
476	                "cannot open file '{}' (no filesystem hook registered)",
477	                fname.escape_ascii()
478	            )));
479	        }
480	    };
481	    let cell = new_file(state)?;
482	    cell.borrow_mut().file = Some(fh);
483	    Ok(())
484	}
485	
486	// ── Close functions ──────────────────────────────────────────────────────────
487	
488	/// Close a regular file via `fclose`. C: `io_fclose`.
489	///
490	/// TODO(port): flush + drop `Box<dyn LuaFileOps>`, map io::Error to file_result.
491	fn io_fclose(state: &mut LuaState) -> Result<usize, LuaError> {
492	    // C: return luaL_fileresult(L, (fclose(p->f) == 0), NULL);
493	    let p_rc = get_lstream(state)?;
494	    // TODO(port): actually flush then drop p.file, capture any error
495	    let _closed = p_rc.borrow_mut().file.take();
496	    state.push(LuaValue::Bool(true));
497	    Ok(1)
498	}
499	
500	/// Close a popen process pipe. C: `io_pclose`.
501	///
502	/// TODO(port): std::process::Child — popen not yet implemented.
503	fn io_pclose(state: &mut LuaState) -> Result<usize, LuaError> {
504	    // C: return luaL_execresult(L, l_pclose(L, p->f));
505	    let p_rc = get_lstream(state)?;
506	    let _closed = p_rc.borrow_mut().file.take();
507	    // TODO(port): wait on the child process and forward its exit code
508	    exec_result(state, 0)
509	}
510	
511	/// Refuse to close a standard-stream handle. C: `io_noclose`.
512	fn io_noclose(state: &mut LuaState) -> Result<usize, LuaError> {
513	    // C: p->closef = &io_noclose;  /* keep file opened */
514	    // C: luaL_pushfail(L); lua_pushliteral(L, "cannot close standard file"); return 2;
515	    let p_rc = get_lstream(state)?;
516	    p_rc.borrow_mut().close_fn = Some(io_noclose); // reinstall to keep the handle alive
517	    state.push(LuaValue::Bool(false));
518	    state.push_string(b"cannot close standard file");
519	    Ok(2)
520	}
521	
522	/// Invoke the stream's close function and mark it closed. C: `aux_close`.
523	fn aux_close(state: &mut LuaState) -> Result<usize, LuaError> {
524	    // C: volatile lua_CFunction cf = p->closef; p->closef = NULL; return (*cf)(L);
525	    let p_rc = get_lstream(state)?;
526	    let cf = p_rc.borrow_mut().close_fn.take().ok_or_else(|| {
527	        LuaError::runtime(format_args!("attempt to close an already-closed file"))
528	    })?;
529	    cf(state)
530	}
531	
532	// ── io.type ──────────────────────────────────────────────────────────────────
533	
534	/// `io.type(x)` — return `"file"`, `"closed file"`, or `false`. C: `io_type`.
535	pub fn io_type(state: &mut LuaState) -> Result<usize, LuaError> {
536	    // C: luaL_checkany(L, 1);
537	    state.check_arg_any(1)?;
538	    // C: p = (LStream *)luaL_testudata(L, 1, LUA_FILEHANDLE);
539	    // C: if (p == NULL) luaL_pushfail(L);
540	    // C: else if (isclosed(p)) lua_pushliteral(L, "closed file");
541	    // C: else lua_pushliteral(L, "file");
542	    let maybe_userdata = state.test_arg_userdata(1, LUA_FILE_HANDLE);
543	    match maybe_userdata {
544	        None => {
545	            state.push(LuaValue::Bool(false));
546	        }
547	        Some(ud) => {
548	            let is_closed = match lookup_lstream(ud.identity()) {
549	                Some(rc) => rc.borrow().is_closed(),
550	                None => true, // unknown userdata with FILE* metatable: treat as closed
551	            };
552	            if is_closed {
553	                state.push_string(b"closed file");
554	            } else {
555	                state.push_string(b"file");
556	            }
557	        }
558	    }
559	    Ok(1)
560	}
561	
562	// ── __tostring metamethod ────────────────────────────────────────────────────
563	
564	/// `tostring(file)` metamethod. C: `f_tostring`.
565	fn f_tostring(state: &mut LuaState) -> Result<usize, LuaError> {
566	    // C: if (isclosed(p)) lua_pushliteral(L, "file (closed)");
567	    // C: else lua_pushfstring(L, "file (%p)", p->f);
568	    let p_rc = get_lstream(state)?;
569	    let closed = p_rc.borrow().is_closed();
570	    if closed {
571	        state.push_string(b"file (closed)");
572	    } else {
573	        // TODO(port): pointer-address representation for the file handle
574	        // C: lua_pushfstring(L, "file (%p)", p->f)
575	        state.push_string(b"file (0x?)");
576	    }
577	    Ok(1)
578	}
579	
580	// ── close / gc ───────────────────────────────────────────────────────────────
581	
582	/// `file:close()`. C: `f_close`.
583	fn f_close(state: &mut LuaState) -> Result<usize, LuaError> {
584	    // C: tofile(L);  /* make sure argument is an open stream */
585	    // C: return aux_close(L);
586	    let _ = tofile(state)?; // validates stream is open before closing
587	    aux_close(state)
588	}
589	
590	/// `io.close([file])`. C: `io_close`.
591	pub fn io_close(state: &mut LuaState) -> Result<usize, LuaError> {
592	    // C: if (lua_isnone(L, 1)) lua_getfield(L, LUA_REGISTRYINDEX, IO_OUTPUT);
593	    if state.type_at(1) == LuaType::None {
594	        state.registry_get(IO_OUTPUT_KEY)?;
595	        state.replace(1);
596	    }
597	    f_close(state)
598	}
599	
600	/// `__gc` / `__close` metamethod — silently close if still open. C: `f_gc`.
601	fn f_gc(state: &mut LuaState) -> Result<usize, LuaError> {
602	    // C: if (!isclosed(p) && p->f != NULL) aux_close(L);  /* ignore errors */
603	    let p_rc = get_lstream(state)?;
604	    let needs_close = {
605	        let p = p_rc.borrow();
606	        !p.is_closed() && p.file.is_some()
607	    };
608	    if needs_close {
609	        // ignore any error from aux_close during GC finalisation
610	        let _ = aux_close(state);
611	    }
612	    Ok(0)
613	}
614	
615	// ── io.open / io.popen / io.tmpfile ─────────────────────────────────────────
616	
617	/// `io.open(filename [, mode])`. C: `io_open`.
618	///
619	/// The file system is reached via `GlobalState::file_open_hook` (registered by
620	/// `lua-cli`) since `std::fs` is banned in `lua-stdlib` per PORTING.md §1.
621	pub fn io_open(state: &mut LuaState) -> Result<usize, LuaError> {
622	    // C: const char *filename = luaL_checkstring(L, 1);
623	    // C: const char *mode = luaL_optstring(L, 2, "r");
624	    let filename: Vec<u8> = state.check_arg_string(1)?;
625	    let mode: Vec<u8> = state.opt_arg_string(2, b"r")?;
626	    // C: luaL_argcheck(L, l_checkmode(md), 2, "invalid mode");
627	    if !check_mode(&mode) {
628	        return Err(LuaError::arg_error(2, "invalid mode"));
629	    }
630	    let hook = state.global().file_open_hook;
631	    match hook {
632	        Some(open_fn) => match open_fn(&filename, &mode) {
633	            Ok(fh) => {
634	                let cell = new_file(state)?;
635	                cell.borrow_mut().file = Some(fh);
636	                // C: return 1; (the file handle userdata is on the stack)
637	                Ok(1)
638	            }
639	            Err(e) => {
640	                let os_err = io::Error::new(
641	                    io::ErrorKind::Other,
642	                    match &e {
643	                        LuaError::Runtime(LuaValue::Str(s)) => {
644	                            String::from_utf8_lossy(s.as_bytes()).into_owned()
645	                        }
646	                        other => format!("{:?}", other),
647	                    },
648	                );
649	                file_result(state, false, Some(&filename), os_err)
650	            }
651	        },
652	        None => {
653	            let os_err = io::Error::new(
654	                io::ErrorKind::Unsupported,
655	                "no filesystem hook registered",
656	            );
657	            file_result(state, false, Some(&filename), os_err)
658	        }
659	    }
660	}
661	
662	/// `io.popen(filename [, mode])`. C: `io_popen`.
663	pub fn io_popen(state: &mut LuaState) -> Result<usize, LuaError> {
664	    // C: luaL_argcheck(L, l_checkmodep(mode), 2, "invalid mode");
665	    // C: p->f = l_popen(L, filename, mode); p->closef = &io_pclose;
666	    let filename: Vec<u8> = state.check_arg_string(1)?;
667	    let mode: Vec<u8> = state.opt_arg_string(2, b"r")?;
668	    if !check_mode_popen(&mode) {
669	        return Err(LuaError::arg_error(2, "invalid mode"));
670	    }
671	    new_pre_file(state)?;
672	    // TODO(port): std::process::Command — spawn child, capture pipe, store in LStream
673	    let _ = (filename, mode);
674	    Err(LuaError::runtime(format_args!(
675	        "'popen' not supported in this build"
676	    )))
677	}
678	
679	/// `io.tmpfile()`. C: `io_tmpfile`.
680	pub fn io_tmpfile(state: &mut LuaState) -> Result<usize, LuaError> {
681	    // C: p->f = tmpfile();
682	    // C: return (p->f == NULL) ? luaL_fileresult(L, 0, NULL) : 1;
683	    new_file(state)?;
684	    // TODO(port): create anonymous temp file (tempfile crate or OS workaround)
685	    Err(LuaError::runtime(format_args!(
686	        "tmpfile not yet implemented"
687	    )))
688	}
689	
690	// ── io.input / io.output ─────────────────────────────────────────────────────
691	
692	/// Retrieve the current default IO file from the registry; error if closed.
693	/// C: `getiofile(L, findex)`.
694	///
695	/// TODO(port): borrow split — returns `&mut dyn LuaFileHandle` while caller also
696	/// needs `&mut LuaState`. Phase B: use `RefCell` inside `LStream`.
697	fn get_io_file<'a>(
698	    state: &'a mut LuaState,
699	    key: &[u8],
700	) -> Result<&'a mut dyn LuaFileHandle, LuaError> {
701	    // C: lua_getfield(L, LUA_REGISTRYINDEX, findex);
702	    // C: p = (LStream *)lua_touserdata(L, -1);
703	    // C: if (isclosed(p)) luaL_error(L, "default %s file is closed", findex+IOPREF_LEN);
704	    state.registry_get(key)?;
705	    // TODO(port): extract &mut LStream from the registry value's userdata payload
706	    let label = &key[IO_PREFIX_LEN..]; // strip "_IO_" for the error message
707	    let p: &mut LStream = todo!("TODO(port): extract LStream from registry userdata");
708	    if p.is_closed() {
709	        return Err(LuaError::runtime(format_args!(
710	            "default {} file is closed",
711	            label.escape_ascii()
712	        )));
713	    }
714	    Ok(p.file.as_mut().expect("open stream has no file handle").as_mut())
715	}
716	
717	/// Generic setter/getter for `io.input` and `io.output`. C: `g_iofile`.
718	fn g_iofile(state: &mut LuaState, key: &[u8], mode: &[u8]) -> Result<usize, LuaError> {
719	    // C: if (!lua_isnoneornil(L, 1)) { ... }
720	    if !matches!(state.type_at(1), LuaType::None | LuaType::Nil) {
721	        if state.type_at(1) == LuaType::String {
722	            // C: opencheck(L, filename, mode);
723	            let filename = state.check_arg_string(1)?;
724	            opencheck(state, &filename, mode)?;
725	        } else {
726	            // C: tofile(L);  /* check that it's a valid file handle */
727	            // C: lua_pushvalue(L, 1);
728	            let _ = tofile(state)?;
729	            state.push_value_at(1);
730	        }
731	        // C: lua_setfield(L, LUA_REGISTRYINDEX, f);
732	        state.registry_set(key)?;
733	    }
734	    // C: lua_getfield(L, LUA_REGISTRYINDEX, f); return 1;
735	    state.registry_get(key)?;
736	    Ok(1)
737	}
738	
739	/// `io.input([file])`. C: `io_input`.
740	pub fn io_input(state: &mut LuaState) -> Result<usize, LuaError> {
741	    g_iofile(state, IO_INPUT_KEY, b"r")
742	}
743	
744	/// `io.output([file])`. C: `io_output`.
745	pub fn io_output(state: &mut LuaState) -> Result<usize, LuaError> {
746	    g_iofile(state, IO_OUTPUT_KEY, b"w")
747	}
748	
749	// ── Read helpers ─────────────────────────────────────────────────────────────
750	
751	/// Read and push a Lua number from `file`. Return `true` on success.
752	/// C: `read_number(L, f)`.
753	fn read_number(
754	    state: &mut LuaState,
755	    file: &mut dyn LuaFileHandle,
756	) -> Result<bool, LuaError> {
757	    // C: do { rn.c = l_getc(rn.f); } while (isspace(rn.c)); /* skip spaces */
758	    let first = loop {
759	        let b = file.read_byte();
760	        if b == EOF_SENTINEL || !(b as u8).is_ascii_whitespace() {
761	            break b;
762	        }
763	    };
764	
765	    let mut rn = ReadNumState::new(first);
766	
767	    // C: test2(&rn, "-+")
768	    rn.try2(file, [b'-', b'+']);
769	
770	    // C: if (test2(&rn, "00")) { if (test2(&rn, "xX")) hex = 1; else count = 1; }
771	    let mut count: usize = 0;
772	    let hex = if rn.try2(file, [b'0', b'0']) {
773	        if rn.try2(file, [b'x', b'X']) {
774	            true
775	        } else {
776	            count = 1;
777	            false
778	        }
779	    } else {
780	        false
781	    };
